"""Class-based runtime store for the system logger; get() is never None.Stages (e.g. tagging) may log full LLM system prompts at DEBUG via get().debug(...)."""from __future__ import annotationsfrom src.core.app_path import AppPathfrom src.core.logger.log_levels import DEBUGfrom src.core.logger.system_logger import SystemLoggerclass SystemLoggerStore:    """Единая точка доступа к системному логгеру. При первом get() создаёт экземпляр при необходимости."""    _current: SystemLogger | None = None    @classmethod    def get(cls) -> SystemLogger:        """Возвращает текущий системный логгер. Если не установлен — создаёт с дефолтными путями и уровнем DEBUG."""        if cls._current is None:            paths = AppPath.from_root()            cls._current = SystemLogger(                logs_dir=paths.logs_dir,                file_name="system",                level=DEBUG,            )        return cls._current    @classmethod    def set(cls, logger: SystemLogger) -> None:        """Устанавливает системный логгер (вызывается из bootstrap)."""        cls._current = logger    @classmethod    def reset(cls) -> None:        """Сбрасывает текущий системный логгер. Следующий get() создаст новый экземпляр."""        cls._current = None    @classmethod    def set_level(cls, level: int | str) -> None:        """Применяет уровень к текущему системному логгеру."""        cls.get().set_level(level)